ruleContent:
$..vodPlayUrl
<js>
// жӣҙж–°зҠ¶жҖҒ
a = "{{$..vodRemarks}}";
b = "{{$..vodTotal}}";
if(!a.match(/е®Ңз»“/)&&!b.match(/^0*$/))a+="(е…ұ"+b+"йӣҶ)";
gx = a+"{{$..vodPubdate##(.+)## вҲҷ $1}}";


// ж јејҸеҢ–и§Јжһҗ
jiexi = eval(String(source.sourceComment)).map($=>'<button onclick="xuan(this,\'.jiexi\')" value="'+$[1]+'"><b>'+$[0]+'</b></button>');


// ж јејҸеҢ–йӣҶж•°
jishu = result.split('#').map($=>{
		$ = $.split('$');
		return '<button onclick="xuan(this,\'.jishu\')" value="'+$[1]+'"><b>'+$[0]+'</b></button>'
	});



// иҝ”еӣһjson
JSON.stringify({
	gx: gx,
	jiexi: '<div>\n\t\t'+jiexi.join('\n\t\t')+'\n</div>',
	jishu: '<div>\n\t\t'+jishu.join('\n\t\t')+'\n</div>'
});
</js>
<title>{{$..vodName}}</title>
<meta name="viewport" content="width=device-width,initial-scale=1.0,minimum-scale=1.0,maximum-scale=1.0,user-scalable=no">
<iframe frameborder="no" allowfullscreen></iframe>
<p></p>
<hr>


<details>
<summary><h3>{{$..vodName}}</h3></summary>
<br>

<!--
<img src="{{$..vodPic}}" onerror="this.src='{{source.sourceIcon}}'">
<p>зүҮеҗҚпјҡ{{$..vodName}}</p>
<p>еҜјжј”пјҡ{{$..vodDirector##,##, }}</p>
<p>зј–еү§пјҡ{{$..vodWriter##,##, }}</p>
<p>дё»жј”пјҡ{{$..vodActor##,##, }}</p>
-->


<p>рҹ“ң еҸҲеҗҚпјҡ{{$..vodSub}}</p>
<p>рҹ”® зұ»еһӢпјҡ{{$..vodArea&&$..vodLang&&$..vodYear##\n## вҲҷ }}</p>
<p>рҹ”Ҙ зғӯеәҰпјҡ{{$..vodHits}}</p>
<p>рҹ“қ иҜ„еҲҶпјҡзҪ‘з«ҷ{{$..vodScore}} | иұҶз“Ј{{$..vodDoubanScore}}</p>
<p>рҹ”– жӣҙж–°пјҡ{{JSON.parse(result).gx}}</p>
<p>рҹҸ·пёҸ ж Үзӯҫпјҡ{{$..vodClass&&$..vodTag##\n|,##, }}</p>
<br>
<p>рҹ“‘ з®Җд»Ӣпјҡ{{$..vodContent##\s*(^|[гҖӮпјҒпјҹ]+[вҖқгҖҚпјүгҖ‘]?)\s*##$1<br>}}</p>
<br>
</details>
<hr>


<div class="jiexi">
<p>и§Јжһҗ</p>
{{JSON.parse(result).jiexi}}
</div>
<hr>


<div class="jishu">
<p>йӣҶж•°</p>
{{JSON.parse(result).jishu}}
</div>
<hr>





<script>
//йҖүдёӯж Үзӯҫ
$=(rule)=>document.querySelectorAll(rule);

//еҲ йҷӨactive
omit=(A)=>Array.from(A,a=>a.className='');

//еўһеҠ active
active=($,i)=>$[i].className='active';

//йҖүжӢ©йӣҶж•°
xuan = (item,type)=>{
		btn = $(type+' button.active');

		if(item.value==btn[0].value)return;
		omit(btn); item.className='active'
		return geturl()
	}


//жӢјжҺҘй“ҫжҺҘ
val=(type)=>$(type+' button.active')[0].value.trim();
geturl=()=>
	$('iframe')[0].src=$('p')[0].innerText=
		val('.jiexi') + val('.jishu');


//еҲқе§ӢеҢ–
(()=>{
		active($('.jiexi button'),0)
		active($('.jishu button'),0)
		return geturl()
	})()
</script>## вҲҷ 0+(\s*)##$1

