ruleContent:
text.е°ҫйЎө@href##_(\d+)##$1###
<js>page=Number(result)+1
url=baseUrl.replace('.html','_')

nurl=[]
for(i=n=2;i<page;i++){
		nurl.push(url+i+'.html,{"retry": 9}')
	}

java.toast('зЁҚзӯүзүҮеҲ»\nгҖҖжӯЈеңЁйЈһйҖҹеҠ иҪҪ')
java.ajaxAll(nurl).map($=>{
		java.toast('еҠ иҪҪдёӯ...\nгҖҖиҝӣеәҰ: '+(Math.floor(n/i*10000)/100)+'%')
		n++
		src += $.body()
	})
java.toast('еҠ иҪҪжҲҗеҠҹ\nгҖҖжӯЈеңЁиҺ·еҸ–еӣҫзүҮ')
src
</js>

.pic-main@img@src
<js>
li='\n'
result.split('\n').map($=>{
		li += '<li><img src="https://m.930tu.com/96kaifa/images/mb-logo.png" data-src="'+$+'"></li>\n'
	});
li
</js>
<meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=0">


<ul id="box">
{{result}}
</ul>


<link rel="stylesheet" href="https://cdn.bootcdn.net/ajax/libs/viewerjs/1.10.1/viewer.min.css">
<script src="https://cdn.bootcdn.net/ajax/libs/viewerjs/1.10.1/viewer.min.js"></script>
<script>
	root = document.getElementById('box')
	lazy = new IntersectionObserver(entires => {
		entires.forEach(item => {
			if(item.isIntersecting){
				item=item.target
				item.src=item.getAttribute('data-src')
				lazy.unobserve(item)
			}
		})
	}, {
		root: root,
		threshold: [0],
		rootMargin:"0px"
	})

imgs = document.getElementsByTagName('img')
Array.from(imgs).forEach(item => {
		lazy.observe(item)
	})

//жҹҘзңӢеӨ§еӣҫжҸ’д»¶
new Viewer(root,{title:false,interval:3000})
</script>

