	                      </span>
	                      <br>
	                      <span class="author">
	                         вҖ”вҖ”${authorname}
	                      </span>
	                  </p>	
	                  <p class="tag">
	                  ${novelsize}вҖў${novelstep_name}вҖў${novel_review_score}<br><br>
	                    ${novelintroshort}<br><br>
	                    ${novelclass_str}<br><br>
	                    ${novelstar}
	                  </p>             
	             </div>	             
	             </div>
