    	  let novelstar = $.novelstar || 0;
    	  let s="";
    	  for(i=0;i<novelstar;i++){s+="вҳ…"}
    	  novelstar=s;
    	  let novelintroshort = $.novelintroshort;
    	  let comment = $.comment || "";
    	  let novelclass_str = $.novelclass_str;

	      html +=`
	         <div class="book">
	            <div class="bookdes">
