class.movurl@a@html&&class.thumb l@html&&class.info@html
<js>
doc=org.jsoup.Jsoup.parse(result);
img=doc.select('img');
info=doc.select('.info').html();

zxb='';dxb='';
list=doc.select('a:not(:last-child)').toArray();

for(i in list){
a='http://www.iyinghua.io'+list[i].select('a').attr('href');
b='http://www.iyinghua.io'+list[list.length-1-i].select('a').attr('href');
zxb=zxb+'<button id="but'+i+'" class="button" value="'+a+'">'+list[i].text()+'</button>';
dxb=dxb+'<button id="dbut'+i+'" class="button" value="'+b+'">'+list[list.length-1-i].text()+'</button>'
}

zx='<div id="zx" style="display:block">'+zxb+'</div>';
dx='<div id="dx" style="display:none">'+dxb+'</div>';


script='(function(){$(".button:first").addClass("upBtn");url=$(".button:first").val();video(url)})();\n$(".button").click(function(){id=$(this).attr("id");\nid="#"+id;\n$(".button").removeClass("upBtn");\n$(id).addClass("upBtn");\nurl=$(id).val();video(url)});\n$("li").click(function(){id=$(this).attr("id");\nid="#"+id;\n$("li").removeClass("active");\n$(id).addClass("active");\nif(id=="#b1"){$("#juji").show();$("#info").hide()}else{$("#info").show();$("#juji").hide()}});$("#dxb").click(function(){if($("#dxb").text()=="еҖ’еәҸ"){$("#dxb").text("жӯЈеәҸ");$("#dx").show();$("#zx").hide();}else{$("#dxb").text("еҖ’еәҸ");$("#dx").hide();$("#zx").show();}}) ';

tap='<div id="tab" style="display:inline;"><ul><li id="b1" class="active">еү§йӣҶ</li><li id="b2">еү§жғ…д»Ӣз»Қ</li><button id="dxb" style="display:inline">еҖ’еәҸ</button></ul></div>';

url='function video(url){$.get(url,function(result){src=result.match(/data-vid="(.*?)"/)[1];jx="https://tup.iyinghua.com/?vid="+src+"&m=1";$("#dd").html(src);$("#ff").attr("src",jx)})};\n'

juji='<div id="juji" style="display:block">'+zx+dx+'</div>';
info='<div id="info" style="display:none">'+img+info+'</div>';

result='<html><head> <script src="https://apps.bdimg.com/libs/jquery/2.1.4/jquery.min.js"> </script> </head>\n<div id="dd">\n</div><iframe src="" width="100%" height="300px" id="ff" scrolling="no"allowfullscreen="true" webkitallowfullscreen="true" frameborder="0" autoplay="true" mozallowfullscreen="true"></iframe>\n'+tap+'\n<div id="html" vspace="120">\n'+juji+info+'\n</div>\n<script>\n'+url+script+'\n</script>\n</html>'
</js>

